urlset:
{%- for file in pages %}
{%- set is_redirect = file.page.meta and file.page.meta.template == "redirect.html" -%}
{%- if not is_redirect and not file.page.is_link and (file.page.abs_url or file.page.canonical_url) -%}
{%- set lastmod = none -%}
{%- if file.page.meta -%}
{%- if file.page.meta.updated -%}
{%- set lastmod = file.page.meta.updated -%}
{%- elif file.page.meta.date and file.page.meta.date.updated -%}
{%- set lastmod = file.page.meta.date.updated -%}
{%- elif file.page.meta.date and file.page.meta.date.created -%}
{%- set lastmod = file.page.meta.date.created -%}
{%- elif file.page.meta.date -%}
{%- set lastmod = file.page.meta.date -%}
{%- endif -%}
{%- endif -%}
{%- if not lastmod and file.page.update_date -%}
{%- set lastmod = file.page.update_date -%}
{%- endif -%}

      {%- if file.page.canonical_url -%}{{ file.page.canonical_url|e }}{%- else -%}{{ file.page.abs_url|e }}{%- endif -%}
{%- if lastmod %}
      {{ lastmod }}
{%- endif %}

{%- endif %}
{%- endfor %}
